public synchronized int vote(String pizza) {
    Integer v = votes.get(pizza);
    int next = v == null ? 1 : v + 1;
    votes.put(pizza, next);
    return next;
}

try (Connection conn = DATA_SOURCE.getConnection()) {
    conn.setAutoCommit(true);
    try (PreparedStatement insert = conn.prepareStatement("INSERT INTO " + table + " (pizza, votes) VALUES (?, 0) ON CONFLICT (pizza) DO NOTHING")) {
        insert.setString(1, pizza);
        insert.executeUpdate();
    }
    int current;
    try (PreparedStatement select = conn.prepareStatement("SELECT votes FROM " + table + " WHERE pizza = ?")) {
        select.setString(1, pizza);
        try (ResultSet rs = select.executeQuery()) {
            current = rs.next() ? rs.getInt(1) : 0;
        }
    }
    int next = current + 1;
    try { Thread.sleep(1); } catch (InterruptedException e) { Thread.currentThread().interrupt(); }
    try (PreparedStatement update = conn.prepareStatement("UPDATE " + table + " SET votes = ? WHERE pizza = ?")) {
        update.setInt(1, next);
        update.setString(2, pizza);
        update.executeUpdate();
    }
    return next;
}

try (Connection conn = DATA_SOURCE.getConnection()) {
    conn.setAutoCommit(true);
    try (PreparedStatement insert = conn.prepareStatement("INSERT INTO " + table + " (pizza, votes) VALUES (?, 0) ON CONFLICT (pizza) DO NOTHING")) {
        insert.setString(1, pizza);
        insert.executeUpdate();
    }
    conn.setAutoCommit(false);
    try {
        try (PreparedStatement lockStmt = conn.prepareStatement("SELECT votes FROM " + table + " WHERE pizza = ? FOR UPDATE")) {
            lockStmt.setString(1, pizza);
            lockStmt.executeQuery().close();
        }
        try (PreparedStatement update = conn.prepareStatement("UPDATE " + table + " SET votes = votes + 1 WHERE pizza = ?")) {
            update.setString(1, pizza);
            update.executeUpdate();
        }
        try (PreparedStatement select = conn.prepareStatement("SELECT votes FROM " + table + " WHERE pizza = ?")) {
            select.setString(1, pizza);
            try (ResultSet rs = select.executeQuery()) {
                int newValue = rs.next() ? rs.getInt(1) : 0;
                conn.commit();
                return newValue;
            }
        }
    } catch (SQLException e) {
        conn.rollback();
        throw e;
    } finally {
        conn.setAutoCommit(true);
    }
}
